-- calc_treatments_total_cases
-- Field: Treatments.TotalCases
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatments_total_cases(p_treatment_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((cases)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatments WHERE treatment_id = p_treatment_id) AND treatment_label = (SELECT NULLIF(treatment_label, '') FROM treatments WHERE treatment_id = p_treatment_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatments_total_successes
-- Field: Treatments.TotalSuccesses
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatments_total_successes(p_treatment_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((successes)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatments WHERE treatment_id = p_treatment_id) AND treatment_label = (SELECT NULLIF(treatment_label, '') FROM treatments WHERE treatment_id = p_treatment_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatments_pooled_success_rate
-- Field: Treatments.PooledSuccessRate
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatments_pooled_success_rate(p_treatment_id TEXT)
RETURNS NUMERIC AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatments_total_cases(p_treatment_id) AS val), __erb_dedup_v2 AS (SELECT calc_treatments_total_successes(p_treatment_id) AS val) SELECT (CASE WHEN ((SELECT val FROM __erb_dedup_v1))::NUMERIC = 0 THEN NULL ELSE ((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v2))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v2))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0), 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

