-- calc_treatment_rankings_total_cases_a
-- Field: TreatmentRankings.TotalCasesA
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_cases_a(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((cases)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_total_successes_a
-- Field: TreatmentRankings.TotalSuccessesA
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_successes_a(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((successes)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_rate_a
-- Field: TreatmentRankings.PooledRateA
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_total_cases_a(p_treatment_ranking_id) AS val), __erb_dedup_v2 AS (SELECT calc_treatment_rankings_total_successes_a(p_treatment_ranking_id) AS val) SELECT (CASE WHEN ((SELECT val FROM __erb_dedup_v1))::NUMERIC = 0 THEN NULL ELSE ((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v2))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v2))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0), 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_total_cases_b
-- Field: TreatmentRankings.TotalCasesB
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_cases_b(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((cases)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_total_successes_b
-- Field: TreatmentRankings.TotalSuccessesB
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_total_successes_b(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((successes)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_rate_b
-- Field: TreatmentRankings.PooledRateB
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_total_cases_b(p_treatment_ranking_id) AS val), __erb_dedup_v2 AS (SELECT calc_treatment_rankings_total_successes_b(p_treatment_ranking_id) AS val) SELECT (CASE WHEN ((SELECT val FROM __erb_dedup_v1))::NUMERIC = 0 THEN NULL ELSE ((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v2))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v2))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0), 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_winner
-- Field: TreatmentRankings.PooledWinner
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_winner(p_treatment_ranking_id TEXT)
RETURNS TEXT AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id) AS val), __erb_dedup_v2 AS (SELECT calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id) AS val) SELECT (CASE WHEN ((SELECT val FROM __erb_dedup_v1) IS NULL OR (SELECT val FROM __erb_dedup_v2) IS NULL) THEN ('')::text ELSE (CASE WHEN (ABS((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v2))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v2))::numeric ELSE NULL END, 0))))::NUMERIC < 0.0000001 THEN ('tie')::text ELSE (CASE WHEN (SELECT val FROM __erb_dedup_v1) > (SELECT val FROM __erb_dedup_v2) THEN ((SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text ELSE ((SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_stratum_count
-- Field: TreatmentRankings.StratumCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_stratum_count(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_strata_won_by_a
-- Field: TreatmentRankings.StrataWonByA
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_strata_won_by_a(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND calc_stratum_summaries_stratum_winner(stratum_summary_id) = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_strata_won_by_b
-- Field: TreatmentRankings.StrataWonByB
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_strata_won_by_b(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_summaries WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND treatment_label = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND calc_stratum_summaries_stratum_winner(stratum_summary_id) = (SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_per_stratum_winner
-- Field: TreatmentRankings.PerStratumWinner
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_treatment_rankings_per_stratum_winner(p_treatment_ranking_id TEXT)
RETURNS TEXT AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_stratum_count(p_treatment_ranking_id) AS val) SELECT (CASE WHEN calc_treatment_rankings_strata_won_by_a(p_treatment_ranking_id) = (SELECT val FROM __erb_dedup_v1) THEN ((SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text ELSE (CASE WHEN calc_treatment_rankings_strata_won_by_b(p_treatment_ranking_id) = (SELECT val FROM __erb_dedup_v1) THEN ((SELECT NULLIF(treatment_b, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id))::text ELSE ('none')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_is_stratum_unanimous
-- Field: TreatmentRankings.IsStratumUnanimous
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_treatment_rankings_is_stratum_unanimous(p_treatment_ranking_id TEXT)
RETURNS BOOLEAN AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_stratum_count(p_treatment_ranking_id) AS val) SELECT ((calc_treatment_rankings_strata_won_by_a(p_treatment_ranking_id) = (SELECT val FROM __erb_dedup_v1) OR calc_treatment_rankings_strata_won_by_b(p_treatment_ranking_id) = (SELECT val FROM __erb_dedup_v1)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_is_reversal
-- Field: TreatmentRankings.IsReversal
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_treatment_rankings_is_reversal(p_treatment_ranking_id TEXT)
RETURNS BOOLEAN AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_is_sign_flip(p_treatment_ranking_id) AS val) SELECT (CASE WHEN (SELECT val FROM __erb_dedup_v1) IS NULL THEN NULL ELSE ((SELECT val FROM __erb_dedup_v1))::text END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_confounders_in_study
-- Field: TreatmentRankings.ConfoundersInStudy
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_confounders_in_study(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM stratum_variables WHERE study = (SELECT NULLIF(study, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) AND calc_stratum_variables_is_confounder(stratum_variable_id) = TRUE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_is_paradox_explained
-- Field: TreatmentRankings.IsParadoxExplained
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_treatment_rankings_is_paradox_explained(p_treatment_ranking_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_treatment_rankings_is_reversal(p_treatment_ranking_id) AND (calc_treatment_rankings_confounders_in_study(p_treatment_ranking_id))::NUMERIC > 0));
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_gap
-- Field: TreatmentRankings.PooledGap
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_gap(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_pooled_rate_a(p_treatment_ranking_id) AS val), __erb_dedup_v2 AS (SELECT calc_treatment_rankings_pooled_rate_b(p_treatment_ranking_id) AS val) SELECT (CASE WHEN (SELECT val FROM __erb_dedup_v1) IS NULL THEN NULL ELSE (ABS((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v2))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v2))::numeric ELSE NULL END, 0))))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_strata_won_by_loser
-- Field: TreatmentRankings.StrataWonByLoser
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_treatment_rankings_pooled_winner(p_treatment_ranking_id) = (SELECT NULLIF(treatment_a, '') FROM treatment_rankings WHERE treatment_ranking_id = p_treatment_ranking_id) THEN (calc_treatment_rankings_strata_won_by_b(p_treatment_ranking_id))::text ELSE (calc_treatment_rankings_strata_won_by_a(p_treatment_ranking_id))::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_paradox_strength
-- Field: TreatmentRankings.ParadoxStrength
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_paradox_strength(p_treatment_ranking_id TEXT)
RETURNS NUMERIC AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_treatment_rankings_stratum_count(p_treatment_ranking_id) AS val), __erb_dedup_v2 AS (SELECT calc_treatment_rankings_pooled_gap(p_treatment_ranking_id) AS val), __erb_dedup_v3 AS (SELECT calc_treatment_rankings_strata_won_by_loser(p_treatment_ranking_id) AS val) SELECT (CASE WHEN ((SELECT val FROM __erb_dedup_v1))::NUMERIC = 0 THEN NULL ELSE ((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v2))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v2))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v3))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v3))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0), 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v3))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v3))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0), 0)))::numeric ELSE NULL END, 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_treatment_rankings_pooled_rate_from_weights_a
-- Field: TreatmentRankings.PooledRateFromWeightsA
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_treatment_rankings_pooled_rate_from_weights_a(p_treatment_ranking_id TEXT)
