-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_domain_expansion_targets_name(p_domain_target_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(domain_target_id, '') FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_domain_expansion_targets_current_imported_count
-- Field: DomainExpansionTargets.CurrentImportedCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_domain_expansion_targets_current_imported_count(p_domain_target_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM studies WHERE domain = CASE WHEN (SELECT NULLIF(legacy_domain_alias, '') FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id) IS NOT NULL THEN ((SELECT NULLIF(legacy_domain_alias, '') FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id))::text ELSE ((SELECT NULLIF(domain, '') FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id))::text END AND is_synthetic = FALSE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_domain_expansion_targets_candidate_queued_count
-- Field: DomainExpansionTargets.CandidateQueuedCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_domain_expansion_targets_candidate_queued_count(p_domain_target_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM candidate_study_catalog WHERE domain = (SELECT NULLIF(domain, '') FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id) AND ingestion_status = 'candidate'))::integer;
$$ LANGUAGE sql STABLE;

-- calc_domain_expansion_targets_projected_count
-- Field: DomainExpansionTargets.ProjectedCount
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_domain_expansion_targets_projected_count(p_domain_target_id TEXT)
RETURNS INTEGER AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_domain_expansion_targets_current_imported_count(p_domain_target_id) AS val), __erb_dedup_v2 AS (SELECT calc_domain_expansion_targets_candidate_queued_count(p_domain_target_id) AS val) SELECT ((COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v2))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v2))::numeric ELSE NULL END, 0)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_domain_expansion_targets_gap_count
-- Field: DomainExpansionTargets.GapCount
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_domain_expansion_targets_gap_count(p_domain_target_id TEXT)
RETURNS INTEGER AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_domain_expansion_targets_projected_count(p_domain_target_id) AS val) SELECT (GREATEST(0, (COALESCE(CASE WHEN ((SELECT target_min_count FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT target_min_count FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN ((SELECT val FROM __erb_dedup_v1))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT val FROM __erb_dedup_v1))::numeric ELSE NULL END, 0))))::integer;
$$ LANGUAGE sql STABLE;

-- calc_domain_expansion_targets_is_under_represented
-- Field: DomainExpansionTargets.IsUnderRepresented
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_domain_expansion_targets_is_under_represented(p_domain_target_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_domain_expansion_targets_projected_count(p_domain_target_id) < (SELECT target_min_count FROM domain_expansion_targets WHERE domain_target_id = p_domain_target_id))::boolean;
$$ LANGUAGE sql STABLE;

